import React, { useState } from 'react';
import GeopoliticalChessboard from './GeopoliticalChessboard';

function App() {
  const [darkMode, setDarkMode] = useState(true);

  const toggleMode = () => {
    setDarkMode(!darkMode);
  };

  const appStyle = {
    backgroundColor: darkMode ? '#111' : '#f5f5f5',
    color: darkMode ? '#fff' : '#000',
    minHeight: '100vh',
    padding: '20px',
    transition: 'all 0.3s ease-in-out',
  };

  const buttonStyle = {
    marginBottom: '20px',
    padding: '8px 16px',
    backgroundColor: darkMode ? '#222' : '#ddd',
    color: darkMode ? '#fff' : '#000',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
  };

  return (
    <div style={appStyle}>
      <h1 style={{ textAlign: 'center' }}>🌍 Geopolitical Chessboard</h1>
      <div style={{ textAlign: 'center' }}>
        <button onClick={toggleMode} style={buttonStyle}>
          Switch to {darkMode ? 'Light' : 'Dark'} Mode
        </button>
      </div>
      <GeopoliticalChessboard darkMode={darkMode} />
    </div>
  );
}

export default App;
